1	import { Request, Response } from 'express';
2	import { createHash } from 'crypto';
3	import { Subject, Test, User, SoloAttempt, SoloSession } from '../models';
4	import {
5	  aiService,
6	  roadmapService,
7	  testResultService,
8	  questionBankService,
9	  userKcMasteryService
10	} from '../services';
11	import { resolveBookContentForAI } from '../services/subjectContent.service';
12	import {
13	  IGenerateTestDTO,
14	  ISubmitTestDTO,
15	  IUserAnswer,
16	  ITestHistory,
17	  IQuestion,
18	  TestGenerationProfile
19	} from '../types';
20	import { success, AppError } from '../utils';
21	import {
22	  formatExpectedAnswer,
23	  clientPrefillValueForQuestion,
24	  gradeAnswer,
25	  sanitizeQuestionForClient
26	} from '../utils/entQuestion.util';
27	import { assertLearnerSubjectAccess } from '../utils/learnerSubjectAccess.util';
28	import { computeTrialTopicMasteryRows } from '../utils/trialTopicMastery.util';
29	
30	class TestController {
31	  private static readonly SOLO_QUESTION_TIME_LIMIT_SEC = 15;
32	
33	  /**
34	   * Точный фильтр кэша теста: предмет + книга + (глава|её отсутствие) + профиль + хэш контента.
35	   * Единый для предгенерационного поиска и для findOrCreateTest — чтобы кэш не «расходился».
36	   */
37	  private buildExactCacheFilter(
38	    dto: IGenerateTestDTO,
39	    profile: TestGenerationProfile,
40	    sourceContentHash: string
41	  ): Record<string, unknown> {
42	    const filter: Record<string, unknown> = {
43	      subjectId: dto.subjectId,
44	      bookId: dto.bookId,
45	      sourceContentHash
46	    };
47	    if (dto.chapterId) {
48	      filter.chapterId = dto.chapterId;
49	    } else {
50	      filter.chapterId = { $exists: false };
51	    }
52	    if (profile === 'regular') {
53	      filter.testProfile = 'regular';
54	    } else {
55	      filter.$or = [{ testProfile: 'ent' }, { testProfile: { $exists: false } }];
56	    }
57	    return filter;
58	  }
59	
60	  /** Найти кэшированный тест по точному ключу (тот же контент → тот же тест). */
61	  private async findCachedTest(
62	    dto: IGenerateTestDTO,
63	    profile: TestGenerationProfile,
64	    sourceContentHash: string
65	  ) {
66	    return Test.findOne(this.buildExactCacheFilter(dto, profile, sourceContentHash)).sort({ createdAt: -1 });
67	  }
68	
69	  private buildDailyPackId(input: {
70	    subjectId: string;
71	    bookId: string;
72	    chapterId?: string;
73	    fullBook?: boolean;
74	    testProfile: TestGenerationProfile;
75	    dateKey: string;
76	  }): string {
77	    const raw = [
78	      input.subjectId,
79	      input.bookId,
80	      input.chapterId || 'full-book',
81	      input.fullBook ? 'full' : 'chapter',
82	      input.testProfile,
83	      input.dateKey
84	    ].join('|');
85	    return `daily-${createHash('sha1').update(raw).digest('hex').slice(0, 16)}`;
86	  }
87	
88	  private getDateKey(date = new Date()): string {
89	    return date.toISOString().slice(0, 10);
90	  }
91	
92	  private startOfToday(date = new Date()): Date {
93	    const d = new Date(date);
94	    d.setHours(0, 0, 0, 0);
95	    return d;
96	  }
97	
98	  private startOfWeek(date = new Date()): Date {
99	    const d = this.startOfToday(date);
100	    const day = d.getDay();
101	    const diff = day === 0 ? 6 : day - 1;
102	    d.setDate(d.getDate() - diff);
103	    return d;
104	  }
105	
106	  private calculateSoloQuestionScore(isCorrect: boolean, responseTimeMs?: number): number {
107	    if (!isCorrect) return 0;
108	    const limitMs = TestController.SOLO_QUESTION_TIME_LIMIT_SEC * 1000;
109	    const safeMs = typeof responseTimeMs === 'number' && Number.isFinite(responseTimeMs) ? responseTimeMs : limitMs;
110	    const remainingSec = Math.max(0, (limitMs - Math.max(0, safeMs)) / 1000);
111	    const score = 1000 * (0.3 + 0.7 * (remainingSec / TestController.SOLO_QUESTION_TIME_LIMIT_SEC));
112	    return Math.round(score);
113	  }
114	
115	  /** Преобразовать topicTitle из AI в topicId для сохранения в тесте */
116	  private resolveTopicTitleToId(generated: { questions: any[] }, book: any): void {
117	    if (!book?.chapters?.length) return;
118	    const allTopics = book.chapters.flatMap((c: any) =>
119	      (c.topics || []).map((t: any) => ({ ...t, _chapterId: c._id }))
120	    );
121	    for (const q of generated.questions || []) {
122	      const topicTitle = q.relatedContent?.topicTitle;
123	      if (topicTitle) {
124	        const topic = allTopics.find(
125	          (t: any) => t.title?.trim()?.toLowerCase() === topicTitle?.trim()?.toLowerCase()
126	        );
127	        if (topic) {
128	          q.relatedContent = {
129	            ...q.relatedContent,
130	            topicId: topic._id,
131	            chapterId: topic._chapterId
132	          };
133	        }
134	        delete q.relatedContent.topicTitle;
135	      }
136	    }
137	  }
138	
139	  private normalizeTestProfile(dto: IGenerateTestDTO): TestGenerationProfile {
140	    return dto.testProfile === 'regular' ? 'regular' : 'ent';
141	  }
142	
143	  /**
144	   * Создать или найти кэш теста по точному ключу.
145	   * Кэш работает ВСЕГДА (раньше отключался при наличии OPENAI_API_KEY → плодились дубликаты).
146	   * allowReuse=false — для пробника (forTrial): всегда свежий тест.
147	   */
148	  private async findOrCreateTest(dto: IGenerateTestDTO, generatedTest: any, allowReuse = true) {
149	    if (dto.chapterId) {
150	      generatedTest.questions = generatedTest.questions.map((q: any) => ({
151	        ...q,
152	        relatedContent: { ...q.relatedContent, chapterId: dto.chapterId as any }
153	      }));
154	    }
155	
156	    const testProfile = this.normalizeTestProfile(dto);
157	
158	    if (allowReuse) {
159	      const cached = await this.findCachedTest(dto, testProfile, generatedTest.sourceContentHash);
160	      if (cached) return cached;
161	    }
162	
163	    return Test.create({
164	      subjectId: dto.subjectId,
165	      bookId: dto.bookId,
166	      chapterId: dto.chapterId || undefined,
167	      questions: generatedTest.questions,
168	      sourceContentHash: generatedTest.sourceContentHash,
169	      testProfile
170	    });
171	  }
172	
173	  /** Сформировать тест для клиента. Подсказки с эталоном — временно, см. SHOW_TEST_CORRECT_ANSWERS. */
174	  private sanitize(test: any) {
175	    const testProfile: TestGenerationProfile =
176	      test.testProfile === 'regular' ? 'regular' : 'ent';
177	    const showDevHints = process.env.SHOW_TEST_CORRECT_ANSWERS !== 'false';
178	    return {
179	      _id: test._id,
180	      subjectId: test.subjectId,
181	      bookId: test.bookId,
182	      chapterId: test.chapterId,
183	      testProfile,
184	      questions: test.questions.map((q: any) => {
185	        const base = sanitizeQuestionForClient(q as IQuestion);
186	        if (showDevHints) {
187	          return {
188	            ...base,
189	            correctAnswerHint: formatExpectedAnswer(q as IQuestion),
190	            devPrefillValue: clientPrefillValueForQuestion(q as IQuestion)
191	          };
192	        }
193	        return base;
194	      }),
195	      createdAt: test.createdAt
196	    };
197	  }
198	
199	  /** Проверить ответы, вернуть userAnswers и счёт */
200	  private checkAnswers(test: any, answers: ISubmitTestDTO['answers']) {
201	    if (answers.length !== test.questions.length) {
202	      throw AppError.badRequest(`Expected ${test.questions.length} answers, received ${answers.length}`);
203	    }
204	
205	    const userAnswers: IUserAnswer[] = [];
206	    let correctCount = 0;
207	
208	    for (const question of test.questions) {
209	      const ua = answers.find((a) => a.questionText === question.questionText);
210	      if (!ua) throw AppError.badRequest(`Missing answer for question: "${question.questionText}"`);
211	
212	      const isCorrect = gradeAnswer(question as IQuestion, ua.selectedOption);
213	      if (isCorrect) correctCount++;
214	      userAnswers.push({ question: question.questionText, selectedOption: ua.selectedOption, isCorrect });
215	    }
216	
217	    const totalQuestions = test.questions.length;
218	    return {
219	      userAnswers,
220	      result: { totalQuestions, correctAnswers: correctCount, scorePercent: Math.round((correctCount / totalQuestions) * 100) }
221	    };
222	  }
223	
224	  /** Узлы КТП ≥ порога (пробник) — для apply-results по персональному роадмапу (фанаут темы книги → КТП) */
225	  private async trialTopicMasteryPayload(
226	    forTrial: boolean,
227	    test: { subjectId: unknown; bookId: unknown; questions: IQuestion[] },
228	    userAnswers: IUserAnswer[]
229	  ): Promise<{ trialTopicMastery: Array<{ subjectId: string; nodeId: string; scorePercent: number }> } | undefined> {
230	    if (!forTrial) return undefined;
231	    const subject = await Subject.findById(String(test.subjectId)).lean();
232	    if (!subject) return { trialTopicMastery: [] };
233	    return {
234	      trialTopicMastery: computeTrialTopicMasteryRows(subject, String(test.bookId), test, userAnswers)
235	    };
236	  }
