238	  // ==================== PUBLIC ENDPOINTS ====================
239	
240	  /** POST /tests/generate-guest */
241	  async generateTestGuest(req: Request, res: Response): Promise<void> {
242	    const dto: IGenerateTestDTO = req.body;
243	    const profile = this.normalizeTestProfile(dto);
244	    const { contentForAI, book } = await resolveBookContentForAI(dto);
245	
246	    // Точный кэш по контенту: тот же материал → тот же тест (без лишнего LLM-вызова).
247	    if (!dto.forTrial) {
248	      const hash = aiService.computeTestContentHash(contentForAI.text, profile, dto.questionCount);
249	      const cached = await this.findCachedTest(dto, profile, hash);
250	      if (cached) {
251	        success(res, this.sanitize(cached), 'Test loaded from cache (same content)', 201);
252	        return;
253	      }
254	    }
255	
256	    const genOpts =
257	      typeof dto.questionCount === 'number' && dto.questionCount > 0
258	        ? { questionCount: dto.questionCount }
259	        : undefined;
260	    const generated = await aiService.generateTest(contentForAI, [], profile, genOpts);
261	    this.resolveTopicTitleToId(generated, book);
262	    const test = await this.findOrCreateTest(dto, generated, !dto.forTrial);
263	    success(res, this.sanitize(test), 'Test generated successfully', 201);
264	  }
265	
266	  /**
267	   * POST /tests/submit-guest
268	   * Гость не имеет истории — отдаём результат + разбор + темы для повторения сразу (без AI).
269	   * AI-объяснение гостю не считаем (дорогой LLM); доступно после авторизации.
270	   */
271	  async submitTestGuest(req: Request, res: Response): Promise<void> {
272	    const { testId, answers, forTrial }: ISubmitTestDTO = req.body;
273	    const test = await Test.findById(testId);
274	    if (!test) throw AppError.notFound('Test not found');
275	
276	    const { userAnswers, result: resultSummary } = this.checkAnswers(test, answers);
277	    const { detailedAnswers, topicsToReview } = await testResultService.buildBreakdown(test, userAnswers);
278	    const trialExtra = await this.trialTopicMasteryPayload(Boolean(forTrial), test, userAnswers);
279	    success(
280	      res,
281	      { testId: test._id, result: resultSummary, detailedAnswers, topicsToReview, ...trialExtra },
282	      'Test submitted successfully'
283	    );
284	  }
