397	  /**
398	   * POST /tests/node-bank (auth) — собрать тест узла из банка вопросов (Фаза 2).
399	   * Покрытие KC + переиспользование item'ов; при нехватке банк дозаполняется и пересобирается.
400	   */
401	  async generateNodeTestFromBank(req: Request, res: Response): Promise<void> {
402	    const userId = (req as any).user?.userId;
403	    const { subjectId, ktpTopicId } = req.body as {
404	      subjectId: string;
405	      ktpTopicId: string;
406	    };
407	    await assertLearnerSubjectAccess(userId, subjectId);
408	    await roadmapService.assertKnowledgeMapTestAllowed(userId, subjectId, `ktp:${ktpTopicId}`);
409	    const test = await questionBankService.assembleNodeTest(subjectId, ktpTopicId, { userId });
410	    success(res, this.sanitize(test), 'Test assembled from question bank', 201);
411	  }
