413	  /** POST /tests/solo/start (auth) */
414	  async startSoloTest(req: Request, res: Response): Promise<void> {
415	    const dto: IGenerateTestDTO & { mode: 'daily_pack' | 'practice' } = req.body;
416	    const userId = (req as any).user?.userId;
417	    await assertLearnerSubjectAccess(userId, dto.subjectId);
418	    await roadmapService.assertKnowledgeMapTestAllowed(userId, dto.subjectId, dto.roadmapNodeId);
419	    const mode = dto.mode === 'practice' ? 'practice' : 'daily_pack';
420	    const dateKey = this.getDateKey();
421	    const dailyPackId = this.buildDailyPackId({
422	      subjectId: dto.subjectId,
423	      bookId: dto.bookId,
424	      chapterId: dto.chapterId,
425	      fullBook: dto.fullBook,
426	      testProfile: this.normalizeTestProfile(dto),
427	      dateKey
428	    });
429	
430	    let test = await Test.findOne({
431	      subjectId: dto.subjectId,
432	      bookId: dto.bookId,
433	      chapterId: dto.chapterId || { $exists: false },
434	      testProfile: this.normalizeTestProfile(dto),
435	      sourceContentHash: dailyPackId
436	    }).sort({ createdAt: -1 });
437	
438	    if (!test) {
439	      const { contentForAI, book } = await resolveBookContentForAI(dto);
440	      const generated = await aiService.generateTest(contentForAI, [], this.normalizeTestProfile(dto));
441	      this.resolveTopicTitleToId(generated, book);
442	      test = await Test.create({
443	        subjectId: dto.subjectId,
444	        bookId: dto.bookId,
445	        chapterId: dto.chapterId || undefined,
446	        questions: generated.questions,
447	        sourceContentHash: dailyPackId,
448	        testProfile: this.normalizeTestProfile(dto)
449	      });
450	    }
451	
452	    /** Один ranked daily pack в календарный день на пользователя, независимо от предмета/книги */
453	    const rankedDailyUsedToday = await SoloAttempt.exists({
454	      userId,
455	      attemptType: 'ranked',
456	      createdAt: { $gte: this.startOfToday() }
457	    });
458	
459	    if (mode === 'daily_pack' && rankedDailyUsedToday) {
460	      throw AppError.badRequest(
461	        'Сегодня вы уже прошли daily pack (доступна одна попытка в день). Выберите Practice или вернитесь завтра.'
462	      );
463	    }
464	
465	    const attemptType = mode === 'daily_pack' ? 'ranked' : 'practice';
466	    const session = await SoloSession.create({
467	      userId,
468	      testId: test._id,
469	      dailyPackId,
470	      mode,
471	      attemptType,
472	      questionTimeLimitSec: TestController.SOLO_QUESTION_TIME_LIMIT_SEC,
473	      currentQuestionIndex: 0,
474	      questionStartedAt: new Date(),
475	      answers: [],
476	      isFinished: false
477	    });
478	
479	    success(
480	      res,
481	      {
482	        ...this.sanitize(test),
483	        mode,
484	        dailyPackId,
485	        attemptType,
486	        soloSessionId: session._id,
487	        soloCurrentQuestionIndex: 0,
488	        soloQuestionStartedAt: session.questionStartedAt,
489	        rankedUsedToday: Boolean(rankedDailyUsedToday),
490	        questionTimeLimitSec: TestController.SOLO_QUESTION_TIME_LIMIT_SEC
491	      },
492	      'Solo test started',
493	      201
494	    );
495	  }
