497	  /** POST /tests/solo/answer (auth) */
498	  async submitSoloAnswer(req: Request, res: Response): Promise<void> {
499	    const userId = (req as any).user?.userId;
500	    const { soloSessionId, questionIndex, selectedOption }: {
501	      soloSessionId: string;
502	      questionIndex: number;
503	      selectedOption: string;
504	    } = req.body;
505	
506	    const session = await SoloSession.findById(soloSessionId);
507	    if (!session) throw AppError.notFound('Solo session not found');
508	    if (session.userId.toString() !== userId) throw AppError.forbidden('Access denied');
509	    if (session.isFinished) throw AppError.badRequest('Solo session already finished');
510	    if (session.currentQuestionIndex !== questionIndex) {
511	      throw AppError.badRequest('Question index mismatch');
512	    }
513	
514	    const test = await Test.findById(session.testId);
515	    if (!test) throw AppError.notFound('Test not found');
516	
517	    const question = test.questions[questionIndex];
518	    if (!question) throw AppError.badRequest('Invalid question index');
519	
520	    const elapsedMs = Math.max(0, Date.now() - session.questionStartedAt.getTime());
521	    const cappedMs = Math.min(elapsedMs, session.questionTimeLimitSec * 1000);
522	    const isCorrect = gradeAnswer(question as IQuestion, selectedOption || '');
523	    const questionScore = this.calculateSoloQuestionScore(isCorrect, cappedMs);
524	
525	    const nextIndex = questionIndex + 1;
526	    const isLastQuestion = nextIndex >= test.questions.length;
527	
528	    session.answers.push({
529	      questionIndex,
530	      selectedOption: selectedOption || '',
531	      isCorrect,
532	      responseTimeMs: cappedMs,
533	      questionScore
534	    });
535	    session.currentQuestionIndex = nextIndex;
536	    session.questionStartedAt = new Date();
537	    if (isLastQuestion) session.isFinished = true;
538	    await session.save();
539	
540	    success(res, {
541	      accepted: true,
542	      questionIndex,
543	      isCorrect,
544	      questionScore,
545	      responseTimeMs: cappedMs,
546	      finished: isLastQuestion,
547	      nextQuestionIndex: isLastQuestion ? null : nextIndex,
548	      questionStartedAt: isLastQuestion ? null : session.questionStartedAt
549	    }, 'Solo answer accepted');
550	  }
