271	            ? `В твоём JSON массив questions содержит ${n} элементов, а нужно РОВНО ${expectedN}. Верни полный JSON-объект: ${expectedN} вопросов, каждый single_choice с ровно 4 вариантами.`
272	            : `В твоём JSON массив questions содержит ${n} элементов, а нужно РОВНО 10 по схеме ЕНТ (номера 1–10 и типы как в задании выше). Верни полный JSON-объект с ключом questions длиной 10 — допиши недостающие вопросы или пересобери массив целиком.`;
273	        chatMessages.push({ role: 'assistant', content: raw }, { role: 'user', content: fixMsg });
274	        continue;
275	      }
276	
277	      try {
278	        questions =
279	          profile === 'regular'
280	            ? parseAndValidateRegularQuestions(rawQuestions, expectedN)
281	            : parseAndValidateEntQuestions(rawQuestions);
282	        break;
283	      } catch (e) {
284	        console.error('🤖 [AI] response:invalid-questions', {
285	          attempt: attempt + 1,
286	          profile,
287	          error: e,
288	          questionsCount: n
289	        });
290	        if (attempt === 1) {
291	          throw e instanceof Error ? e : new Error('Invalid questions from model.');
292	        }
293	        chatMessages.push(
294	          { role: 'assistant', content: raw },
295	          {
296	            role: 'user',
297	            content: `Массив из ${expectedN} элементов есть, но проверка не прошла: ${
298	              e instanceof Error ? e.message : String(e)
299	            }. Исправь структуру каждого вопроса и верни полный JSON с questions (ровно ${expectedN} элементов).`
300	          }
301	        );
302	      }
303	    }
304	
305	    if (!questions) {
306	      throw new Error('Не удалось сгенерировать вопросы после повторной попытки.');
307	    }
308	
309	    for (const question of questions) {
310	      if (!question.relatedContent?.pages?.length) {
311	        question.relatedContent = { ...question.relatedContent, pages: [1] };
312	      }
313	    }
314	
315	    console.log('🤖 [AI] generateTest:done', { questionsCount: questions.length });
316	    return { questions, sourceContentHash };
