319	  /**
320	   * Несколько подряд серий по 10 вопросов (ЕНТ) без дублирования смысла между сериями.
321	   */
322	  private async generateEntBatchedTest(
323	    content: IContentForAI,
324	    _previousQuestions: string[],
325	    total: number
326	  ): Promise<IGeneratedTest> {
327	    const batches = total / 10;
328	    const all: IQuestion[] = [];
329	    let prev = [..._previousQuestions];
330	    for (let b = 0; b < batches; b++) {
331	      const paddedContent: IContentForAI =
332	        batches > 1 && b > 0
333	          ? {
334	              ...content,
335	              text:
336	                `${content.text}\n\n(Продолжение: серия ${b + 1} из ${batches}, по 10 вопросов в формате ЕНТ. Не повторяй смыслы вопросов из предыдущих серий; опирайся на другие разделы и факты учебного материала.)`
337	            }
338	          : content;
339	      const part = await this.generateTest(paddedContent, prev, 'ent');
340	      all.push(...part.questions);
341	      prev = [
342	        ...prev,
343	        ...part.questions.map((q) => Buffer.from(q.questionText).toString('base64'))
344	      ];
345	    }
346	    for (const question of all) {
347	      if (!question.relatedContent?.pages?.length) {
348	        question.relatedContent = { ...question.relatedContent, pages: [1] };
349	      }
350	    }
351	    const sourceContentHash = this.computeTestContentHash(content.text, 'ent', total);
352	    return { questions: all, sourceContentHash };
353	  }
